mapper.select:
SELECT application_case_id
FROM auto_prep_case_dedupe
WHERE user_id = #{userId}
  AND file_id = #{fileId}
FOR UPDATE

mapper.update:
UPDATE auto_prep_case_dedupe
SET application_case_id = #{applicationCaseId}
WHERE user_id = #{userId}
  AND file_id = #{fileId}
  AND application_case_id IS NULL

mapper.delete:
